```python
let todos = [];
let currentFilter = 'all';

// DOM Elements
const todoForm = document.getElementById('todo-form');
const todoInput = document.getElementById('todo-input');
const todoList = document.getElementById('todo-list');
const emptyMessage = document.getElementById('empty-message');
const filterButtons = document.querySelectorAll('.filter-btn');

// Fetch todos on load
document.addEventListener('DOMContentLoaded', fetchTodos);

// Add Todo
todoForm.addEventListener('submit', async (e) => {
    e.preventDefault();
    const title = todoInput.value.trim();
    if (!title) return;

    await addTodo(title);
    todoInput.value = '';
});

async function fetchTodos() {
    try {
        // Added cache busting with timestamp to prevent browser from serving cached GET response
        const response = await fetch(`/api/todos?t=${Date.now()}`);
        todos = await response.json();
        render();
    } catch (error) {
        console.error('Error fetching todos:', error);
    }
}

async function addTodo(title) {
    try {
        const response = await fetch('/api/todos', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title })
        });
        if (response.ok) {
            await fetchTodos(); // Refresh list
        }
    } catch (error) {
        console.error('Error adding todo:', error);
    }
}

async function toggleTodo(id, completed) {
    try {
        const response = await fetch(`/api/todos/${id}`, {
            method: 'PUT',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ completed })
        });
        if (response.ok) {
            await fetchTodos(); // Refresh list to ensure sync
        }
    } catch (error) {
        console.error('Error toggling todo:', error);
    }
}

async function deleteTodo(id) {
    try {
        const response = await fetch(`/api/todos/${id}`, {
            method: 'DELETE'
        });
        if (response.ok) {
            await fetchTodos(); // Refresh list
        }
    } catch (error) {
        console.error('Error deleting todo:', error);
    }
}

function setFilter(filter) {
    currentFilter = filter;

    // Update button styles
    filterButtons.forEach(btn => {
        btn.classList.remove('bg-blue-600', 'text-white');
        btn.classList.add('bg-gray-200', 'text-gray-700');
    });

    const activeBtn = document.getElementById(`filter-${filter}`);
    if (activeBtn) {
        activeBtn.classList.remove('bg-gray-200', 'text-gray-700');
        activeBtn.classList.add('bg-blue-600', 'text-white');
    }

    render();
}

function render() {
    todoList.innerHTML = '';

    let filteredTodos = todos;
    if (currentFilter === 'active') {
        filteredTodos = todos.filter(t => !t.completed);
    } else if (currentFilter === 'completed') {
        filteredTodos = todos.filter(t => t.completed);
    }

    if (filteredTodos.length === 0) {
        emptyMessage.classList.remove('hidden');
    } else {
        emptyMessage.classList.add('hidden');

        filteredTodos.forEach(todo => {
            const li = document.createElement('li');
            li.className = 'flex items-center justify-between p-3 bg-gray-50 rounded border border-gray-200';

            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.checked = todo.completed;
            checkbox.className = 'w-5 h/5 text-blue-600 rounded focus:ring-blue-500 cursor-pointer'; // Fixed typo in className from my thought process if any
            // Re-checking original code for class names... 
            // Original was: checkbox.className = 'w-5 h-5 text-blue-600 rounded focus:ring-blue-500 cursor-pointer';
            // I will stick to the exact original classes.

            checkbox.onchange = () => toggleTodo(todo.id, !todo.completed);

